// netlify/functions/autopost.js
// TV thumbnail generator + Telegram & Facebook poster
// Place this file at: netlify/functions/autopost.js in your repo

const https = require('https');

const STUDIO_B64 = '';


const CAT_COLORS = {
  'POLITICS':'#1a6b3c','CINEMA':'#6C3FC5','SPORTS':'#1A7C3E','CRICKET':'#1A7C3E',
  'TELANGANA':'#7c3aed','ANDHRA':'#0369a1','NATIONAL':'#b45309','BUSINESS':'#b45309','LOCALNEWS':'#0369a1'
};

function esc(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

function buildSVG(article) {
  const title    = esc(article.title || '');
  const category = esc((article.category || 'NEWS').toUpperCase());
  const catColor = CAT_COLORS[category] || '#c0392b';

  // Split title into 2 lines
  const words = title.split(' ');
  let l1='', l2='';
  for(const w of words){
    if(l1.length + w.length < 42) l1 += (l1?' ':'')+w;
    else l2 += (l2?' ':'')+w;
  }
  if(l2.length>50) l2=l2.substring(0,48)+'...';

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" width="1200" height="630" viewBox="0 0 1200 630">
<defs>
<linearGradient id="ov" x1="0" y1="0" x2="0" y2="1">
  <stop offset="0%"   stop-color="#000" stop-opacity="0.04"/>
  <stop offset="55%"  stop-color="#000" stop-opacity="0.20"/>
  <stop offset="72%"  stop-color="#000" stop-opacity="0.62"/>
  <stop offset="100%" stop-color="#000" stop-opacity="0.90"/>
</linearGradient>
<filter id="ts"><feDropShadow dx="1" dy="1" stdDeviation="2.5" flood-opacity="0.8"/></filter>
<filter id="ts2"><feDropShadow dx="1" dy="1" stdDeviation="4" flood-opacity="0.95"/></filter>
</defs>

<!-- Background -->
<image href="data:image/jpeg;base64,${STUDIO_B64}" x="0" y="0" width="1200" height="630" preserveAspectRatio="xMidYMid slice"/>
<!-- Dark overlay -->
<rect width="1200" height="630" fill="url(#ov)"/>

<!-- Corner accents -->
<polyline points="14,60 14,14 60,14" fill="none" stroke="#f0c040" stroke-width="3.5"/>
<polyline points="1186,570 1186,616 1140,616" fill="none" stroke="#f0c040" stroke-width="3.5"/>

<!-- LIVE badge -->
<rect x="18" y="16" width="132" height="46" rx="6" fill="#CC0000"/>
<text x="30" y="47" font-family="Arial,sans-serif" font-size="22" font-weight="bold" fill="#fff" filter="url(#ts)">&#x25CF; LIVE</text>

<!-- Brand TELUGU SCOOP LIVE -->
<text font-family="Arial,sans-serif" font-size="44" font-weight="bold" text-anchor="middle" filter="url(#ts)">
  <tspan x="600" y="56" fill="#fff">TELUGU </tspan><tspan fill="#f0c040">SCOOP</tspan><tspan fill="#fff"> LIVE</tspan>
</text>

<!-- Tagline -->
<text x="600" y="83" font-family="Noto Sans Telugu,Arial Unicode MS,Arial,sans-serif" font-size="19" font-weight="bold" fill="rgba(255,255,255,0.9)" text-anchor="middle">&#x0C24;&#x0C46;&#x0C32;&#x0C41;&#x0C17;&#x0C41; &#x0C35;&#x0C3E;&#x0C30;&#x0C4D;&#x0C24;&#x0C32;&#x0C41; &#x2022; REAL TIME</text>

<!-- Category badge -->
<rect x="18" y="444" width="175" height="36" rx="3" fill="#f0c040"/>
<text x="30" y="468" font-family="Arial,sans-serif" font-size="20" font-weight="bold" fill="#111">${category}</text>

<!-- Breaking bar -->
<rect x="0" y="490" width="1200" height="90" fill="${catColor}"/>
<rect x="0" y="488" width="1200" height="4" fill="#f0c040"/>
<rect x="0" y="578" width="1200" height="4" fill="#f0c040"/>

<!-- BREAKING NEWS label -->
<rect x="14" y="498" width="238" height="36" rx="3" fill="#f0c040"/>
<text x="22" y="522" font-family="Arial,sans-serif" font-size="20" font-weight="bold" fill="#111">BREAKING NEWS</text>

<!-- Headline -->
<text x="262" y="524" font-family="Noto Sans Telugu,Arial Unicode MS,Arial,sans-serif" font-size="34" font-weight="bold" fill="#fff" filter="url(#ts2)">${l1}</text>
<text x="262" y="566" font-family="Noto Sans Telugu,Arial Unicode MS,Arial,sans-serif" font-size="34" font-weight="bold" fill="#fff" filter="url(#ts2)">${l2}</text>

<!-- Watermark -->
<text x="1184" y="572" font-family="Arial,sans-serif" font-size="13" font-style="italic" fill="rgba(255,255,255,0.28)" text-anchor="end">teluguscooplive.com</text>

<!-- Ticker bar -->
<rect x="0" y="582" width="1200" height="48" fill="#0D2B5E"/>
<rect x="0" y="580" width="1200" height="3" fill="#f0c040"/>
<rect x="0" y="582" width="100" height="48" fill="#f0c040"/>
<text x="50" y="612" font-family="Arial,sans-serif" font-size="17" font-weight="bold" fill="#0D2B5E" text-anchor="middle">&#x1F4FA; TSL</text>
<text x="108" y="612" font-family="Noto Sans Telugu,Arial Unicode MS,Arial,sans-serif" font-size="15" fill="#fff">TELUGU SCOOP LIVE &#x2022; &#x0C24;&#x0C46;&#x0C32;&#x0C41;&#x0C17;&#x0C41; &#x0C35;&#x0C3E;&#x0C30;&#x0C4D;&#x0C24;&#x0C32;&#x0C41; &#x2022; REAL TIME &#x2022; BREAKING NEWS</text>
</svg>`
  .replace(/\$\{STUDIO_B64\}/g, STUDIO_B64)
  .replace(/\$\{catColor\}/g, catColor)
  .replace(/\$\{category\}/g, category)
  .replace(/\$\{l1\}/g, l1)
  .replace(/\$\{l2\}/g, l2);
}

async function svgToPng(svgStr) {
  try {
    const sharp = require('sharp');
    return await sharp(Buffer.from(svgStr))
      .resize(1200, 630)
      .png({ quality: 97, compressionLevel: 6 })
      .toBuffer();
  } catch(e) {
    console.warn('[autopost] sharp unavailable:', e.message);
    return Buffer.from(svgStr); // return SVG if sharp not installed
  }
}

function multipartPost(urlStr, fields, files) {
  const boundary = 'Boundary' + Date.now();
  const CRLF = '\r\n';
  const parts = [];
  for (const [k, v] of Object.entries(fields)) {
    parts.push(Buffer.from(`--${boundary}${CRLF}Content-Disposition: form-data; name="${k}"${CRLF}${CRLF}${v}${CRLF}`));
  }
  for (const [k, {data, filename, ct}] of Object.entries(files)) {
    parts.push(Buffer.concat([
      Buffer.from(`--${boundary}${CRLF}Content-Disposition: form-data; name="${k}"; filename="${filename}"${CRLF}Content-Type: ${ct}${CRLF}${CRLF}`),
      data,
      Buffer.from(CRLF)
    ]));
  }
  parts.push(Buffer.from(`--${boundary}--${CRLF}`));
  const body = Buffer.concat(parts);
  const u = new URL(urlStr);
  return new Promise((res, rej) => {
    const req = https.request({
      hostname: u.hostname, path: u.pathname + u.search, port: 443, method: 'POST',
      headers: { 'Content-Type': `multipart/form-data; boundary=${boundary}`, 'Content-Length': body.length }
    }, r => {
      let d=''; r.on('data',c=>d+=c);
      r.on('end',()=>{ try{res(JSON.parse(d));}catch(e){res({_raw:d});} });
    });
    req.on('error', rej);
    req.write(body); req.end();
  });
}

exports.handler = async (event) => {
  const CORS = { 'Access-Control-Allow-Origin':'*', 'Access-Control-Allow-Headers':'Content-Type', 'Content-Type':'application/json' };
  if (event.httpMethod === 'OPTIONS') return { statusCode:204, headers:CORS, body:'' };
  if (event.httpMethod !== 'POST') return { statusCode:405, headers:CORS, body:'{"error":"POST only"}' };

  let p;
  try { p = JSON.parse(event.body); } catch(e) { return { statusCode:400, headers:CORS, body:'{"error":"bad json"}' }; }

  const { article, tg_token, tg_chat_id, fb_token, fb_page_id } = p;
  if (!article?.title) return { statusCode:400, headers:CORS, body:'{"error":"article.title required"}' };

  const results = {};
  const svg = buildSVG(article);
  const imgBuf = await svgToPng(svg);
  const isActualPng = imgBuf[0]===0x89 && imgBuf[1]===0x50; // PNG magic bytes
  const imgCt = isActualPng ? 'image/png' : 'image/svg+xml';
  const imgFilename = isActualPng ? 'thumbnail.png' : 'thumbnail.svg';

  const siteUrl = 'https://teluguscooplive.netlify.app';
  const artUrl  = `${siteUrl}/?article=${article.id||article.slug||''}`;
  const caption = `📰 ${(article.category||'NEWS').toUpperCase()}\n\n<b>${article.title}</b>`
    + (article.excerpt ? `\n\n${article.excerpt.substring(0,180)}` : '')
    + `\n\n🔗 ${artUrl}\n\n#TeluguNews #TeluguScoopLive`;
  const captionFb = caption.replace(/<[^>]+>/g,'');

  // Telegram
  if (tg_token && tg_chat_id) {
    try {
      const r = await multipartPost(
        `https://api.telegram.org/bot${tg_token}/sendPhoto`,
        { chat_id: tg_chat_id, caption, parse_mode:'HTML',
          reply_markup: JSON.stringify({inline_keyboard:[[{text:'📖 Read Full Article',url:artUrl}]]}) },
        { photo: { data:imgBuf, filename:imgFilename, ct:imgCt } }
      );
      results.telegram = r.ok ? {ok:true} : {ok:false, error:r.description};
    } catch(e) { results.telegram = {ok:false, error:e.message}; }
  }

  // Facebook
  if (fb_token && fb_page_id) {
    try {
      const r = await multipartPost(
        `https://graph.facebook.com/v19.0/${fb_page_id}/photos`,
        { access_token: fb_token, caption: captionFb },
        { source: { data:imgBuf, filename:imgFilename, ct:imgCt } }
      );
      results.facebook = r.id ? {ok:true} : {ok:false, error:r.error?.message||JSON.stringify(r)};
    } catch(e) { results.facebook = {ok:false, error:e.message}; }
  }

  return { statusCode:200, headers:CORS, body:JSON.stringify({ok:true, results}) };
};
